# 2.  AG2 — 15-day city temperature & precip forecast for major ERCOT metros
# ══════════════════════════════════════════════════════════════════════════════

AG2_BASE = "https://www.wsitrader.com/Services/CSVDownloadService.svc"

AG2_ERCOT_CITIES = {
    "Abilene, TX", "Austin, TX", "Corpus Christi, TX", "Dallas Fort Worth, TX",
    "Galveston, TX", "Houston Iah, TX", "Lubbock, TX", "Midland, TX",
    "San Antonio, TX", "Waco, TX", "Wichita Falls, TX", "Brownsville, TX",
    "Laredo Afb, TX", "Victoria, TX",
}


def _ag2_auth_params():
    return {
        "Account":  os.environ.get("AG2_ACCOUNT", ""),
        "Profile":  os.environ.get("AG2_PROFILE", ""),
        "Password": os.environ.get("AG2_PASSWORD", ""),
    }


def _ag2_csv_get(endpoint, extra_params, timeout=25):
    url    = f"{AG2_BASE}/{endpoint}"
    params = {**_ag2_auth_params(), **extra_params}
    try:
        r = requests.get(url, params=params, timeout=timeout)
        r.raise_for_status()
        return r.text
    except Exception as e:
        print(f"  WARN [AG2 Trader] {endpoint} — {e}")
        return ""


def _parse_ag2_csv(csv_text):
    """
    Parse WSI/AG2 Trader CSV wide format.
    Row 1: metadata title (skipped)
    Row 2: headers — first col is blank/city, remaining cols are dates (M/D/YYYY) + Normals
    Row 3+: data rows — first col = "City Name High" or "City Name Low", rest = values

    Returns list of dicts with keys: city, metric (High/Low), and date->value pairs.
    """
    import csv, io
    rows = []
    if not csv_text or not csv_text.strip():
        return rows
    try:
        lines = [l for l in csv_text.strip().splitlines() if l.strip()]
        if not lines:
            return rows
        # Skip metadata title row (contains 'Forecast' or ' - ')
        first = lines[0]
        if 'Forecast' in first or ' - ' in first or not any(c.isdigit() for c in first):
            lines = lines[1:]
        if not lines:
            return rows
        reader = csv.reader(io.StringIO(chr(10).join(lines)))
        headers = None
        for row in reader:
            if headers is None:
                headers = [h.strip() for h in row]
                continue
            if not row or not row[0].strip():
                continue
            record = {}
            for i, val in enumerate(row):
                key = headers[i] if i < len(headers) else f"col{i}"
                record[key.strip()] = val.strip()
            rows.append(record)
        if rows:
            print(f"    DEBUG AG2 parsed {len(rows)} rows, cols: {list(rows[0].keys())[:6]}")
    except Exception as e:
        print(f"  WARN [AG2 CSV parse] {e}")
    return rows

def collect_ag2_weather():
    acct = os.environ.get("AG2_ACCOUNT", "")
    if not acct:
        print("  SKIP [AG2 Trader] AG2_ACCOUNT not set")
        return {"weather": {}}

    print("  Pulling AG2 Trader 15-day city forecasts for ERCOT metros...")

    minmax_csv  = _ag2_csv_get("GetCityTableForecast", {
        "IsCustom": "false", "CurrentTabName": "MinMax", "TempUnits": "F",
        "Id": "allcities", "Region": "NA",
    })
    minmax_rows = _parse_ag2_csv(minmax_csv)

    pop_csv  = _ag2_csv_get("GetCityTableForecast", {
        "IsCustom": "false", "CurrentTabName": "POP", "TempUnits": "F",
        "Id": "allcities", "Region": "NA",
    })
    pop_rows = _parse_ag2_csv(pop_csv)

    cities_out = {}
    ag2_lower  = {c.lower(): c for c in AG2_ERCOT_CITIES}

    # WSI wide format: first column = "City Name High" / "City Name Low"
    # remaining columns = dates like "7/1/2026", "7/2/2026", ...
    from datetime import datetime as _dt

    def _parse_wide_rows(rows):
        """Extract {canonical_city: {metric: {date: value}}} from wide-format rows."""
        result = {}
        for row in rows:
            keys = list(row.keys())
            if not keys:
                continue
            label = row.get(keys[0], '').strip()
            metric = None
            clean_label = label
            for suffix in [' High', ' Low', ' PoP', ' POP', ' Precip']:
                if label.upper().endswith(suffix.upper()):
                    metric = suffix.strip().lower()
                    clean_label = label[:len(label)-len(suffix)].strip()
                    break
            if metric is None:
                continue
            import re as _re2
            # Remove airport code suffix like "(KDFW)", strip extra spaces
            clean = _re2.sub(r'\s*\([^)]*\)', '', clean_label).strip()
            clean = _re2.sub(r'\s+', ' ', clean)
            # WSI format: "Dallas Fort Worth TX" (space before state, no comma)
            # Our format:  "Dallas Fort Worth, TX" (comma before state)
            # Normalize: insert comma before 2-letter state code if missing
            clean = _re2.sub(r'\s+([A-Z]{2})$', r', \1', clean)
            city_key = clean.lower()
            canonical = ag2_lower.get(city_key)
            if not canonical:
                # Try title-casing variants
                for variant in [clean.title(), clean.upper(), clean]:
                    canonical = ag2_lower.get(variant.lower())
                    if canonical:
                        break
            if not canonical:
                # Last resort: match on city name portion only (before comma)
                city_part = city_key.split(',')[0].strip()
                for ag2_name, ag2_canonical in ag2_lower.items():
                    if ag2_name.split(',')[0].strip() == city_part:
                        canonical = ag2_canonical
                        break
            if not canonical:
                continue
            dates = {}
            for col, val in row.items():
                col = col.strip()
                if col == keys[0] or col == 'Normals' or not col:
                    continue
                try:
                    d = _dt.strptime(col, "%m/%d/%Y").strftime("%Y-%m-%d")
                    dates[d] = int(safe_float(val or 0))
                except ValueError:
                    pass
            if dates:
                result.setdefault(canonical, {})[metric] = dates
        return result

    minmax_parsed = _parse_wide_rows(minmax_rows)
    pop_parsed    = _parse_wide_rows(pop_rows)

    for city_name, metrics in minmax_parsed.items():
        hi_days  = metrics.get('high', {})
        lo_days  = metrics.get('low',  {})
        pop_days = pop_parsed.get(city_name, {}).get('pop',
                   pop_parsed.get(city_name, {}).get('precip', {}))
        all_dates = sorted(set(list(hi_days.keys()) + list(lo_days.keys())))[:15]
        days_list = [{"date": dt, "high": hi_days.get(dt, 0),
                      "low": lo_days.get(dt, 0), "precip_pct": pop_days.get(dt, 0)}
                     for dt in all_dates]
        if days_list:
            cities_out[city_name] = {"days": days_list}

    n_days = len(next(iter(cities_out.values()))["days"]) if cities_out else 0
    print(f"    AG2: {len(cities_out)} cities · {n_days} days each")
    if not cities_out and minmax_rows:
        sample = minmax_rows[:3]
        print(f"    DEBUG — cols: {list(sample[0].keys())[:8] if sample else []}")
        first_key = list(sample[0].keys())[0] if sample else ''
        all_labels = [r.get(first_key, '') for r in minmax_rows]
        tx_labels = [l for l in all_labels if ' TX' in l or ', TX' in l]
        print(f"    DEBUG — TX city labels found ({len(tx_labels)}): {tx_labels[:10]}")
        print(f"    DEBUG — sample labels (first 5): {all_labels[:5]}")

    return {
        "weather": {
            "cities":       cities_out,
            "generated_at": datetime.utcnow().isoformat() + "Z",
            "source":       "AG2 Trader (wsitrader.com)",
        }
    }


